  MaxTimeout = -1,
};
var client = new RestClient(options);
var request = new RestRequest("/api/v1/watchlists/{{watchlistId}}", Method.Put);
request.AddHeader("X-SECURITY-TOKEN", "ENTER_OBTAINED_SECURITY_TOKEN");
request.AddHeader("CST", "ENTER_OBTAINED_CST_TOKEN");
request.AddHeader("Content-Type", "application/json");
var body = @"{" + "\n" +
@"    ""epic"": ""SILVER""" + "\n" +
@"}";
request.AddStringBody(body, DataFormat.Json);
RestResponse response = await client.ExecuteAsync(request);
Console.WriteLine(response.Content);

OkHttpClient client = new OkHttpClient().newBuilder()
  .build();
MediaType mediaType = MediaType.parse("application/json");
RequestBody body = RequestBody.create(mediaType, "{\n    \"epic\": \"SILVER\"\n}");
Request request = new Request.Builder()
  .url("https://api-capital.backend-capital.com/api/v1/watchlists/{{watchlistId}}")
  .method("PUT", body)
  .addHeader("X-SECURITY-TOKEN", "ENTER_OBTAINED_SECURITY_TOKEN")
  .addHeader("CST", "ENTER_OBTAINED_CST_TOKEN")
  .addHeader("Content-Type", "application/json")
  .build();
Response response = client.newCall(request).execute();

var myHeaders = new Headers();
myHeaders.append("X-SECURITY-TOKEN", "ENTER_OBTAINED_SECURITY_TOKEN");
myHeaders.append("CST", "ENTER_OBTAINED_CST_TOKEN");
myHeaders.append("Content-Type", "application/json");

var raw = JSON.stringify({
  "epic": "SILVER"
});

var requestOptions = {
  method: 'PUT',
  headers: myHeaders,
  body: raw,
  redirect: 'follow'
};

fetch("https://api-capital.backend-capital.com/api/v1/watchlists/{{watchlistId}}", requestOptions)
  .then(response => response.text())
  .then(result => console.log(result))
  .catch(error => console.log('error', error));

const request = require('request');
let options = {
  'method': 'PUT',
  'url': 'https://api-capital.backend-capital.com/api/v1/watchlists/{{watchlistId}}',
  'headers': {
    'X-SECURITY-TOKEN': 'ENTER_OBTAINED_SECURITY_TOKEN',
    'CST': 'ENTER_OBTAINED_CST_TOKEN',
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
    "epic": "SILVER"
  })

};
request(options, (error, response) => {
  if (error) throw new Error(error);
  console.log(response.body);
});

